var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이쪽이 입구예요.","JPN":"こっちが入り口です。","ENG":"This is the entrance.","TWN":"入口在這邊。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"저도 정원 안으로 들어가는 건 오랜만이라 엄청 긴장되네요.","JPN":"私も庭園に入るのは久しぶりで、すごく緊張します。","ENG":"It's been a long time since I went inside the garden, so I'm really nervous.","TWN":"我也很久沒進花園了，感覺好緊張啊。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"입구 찾기도 쉽지 않군. 혼자 다니면 시작부터 길을 잃겠어.","JPN":"入り口を探すのも大変だな。1人だったらすぐ道に迷いそうだ。","ENG":"Even finding the entrance is hard. I'd get lost immediately if I went in there alone.","TWN":"找個入口也真不容易啊。一個人走的話一開始就會迷路。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니가 일부러 미로처럼 만들었어요. 못된 침식체들이 바깥으로 나오지 못하게 하려고요.","JPN":"悪い侵食体が外に出ないよう、お母さんがわざと迷路みたいにしてるんです。","ENG":"Mother made it like a maze on purpose. So that those mean C.O.s could not escape.","TWN":"媽媽故意把這裡弄成迷宮的樣子，是為了不讓那些可惡的侵蝕體跑出來。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"침식체들이 안쪽에서 나오는 거라고?","JPN":"この中から侵食体が出てくるの？","ENG":"The C.O.s are coming out from in there?","TWN":"侵蝕體是從裡面出來的嗎？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"맞아요.","JPN":"そうです。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"원래는 집 근처에도 자주 나타났었는데, 어머니가 침식체들을 막으러 떠난 뒤로 집 주변은 안전해졌어요.","JPN":"前は家の近くでもよく現れたんですけど、お母さんが侵食体を止めに行ってから、家の周りは安全になりました。","ENG":"They used to appear frequently near our house, but ever since Mother left to stop them, the area around the house became safe.","TWN":"原本它們經常出現在家附近，但自從媽媽擋住了它們，家的周圍就安全了。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"저 안뜰에서 열심히 싸우고 계신 덕분이겠죠. 관리국의 영웅처럼요.","JPN":"きっとあの中で一生懸命戦っているお母さんのおかげですね。管理局の英雄みたいに。","ENG":"It's all thanks to her fighting them off in the inner yard. Like an Administration hero.","TWN":"那一定是因為媽媽在內院裡拼命戰鬥的緣故吧。就像管理局的英雄們一樣。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"여길 다른 사람이랑 들어오는 건 처음이에요.","JPN":"ここに他人と一緒に入るのは初めてです。","ENG":"This is my first time coming here with someone else.","TWN":"這是我第一次和別人一起來這裡。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어때요? 엄청 아름답죠?","JPN":"どうですか？　すごくきれいでしょう？","ENG":"What do you think? Isn't it beautiful?","TWN":"怎麼樣？很美吧？"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"온통 식물로 가득하네. 파블린의 취향다워.","JPN":"植物でいっぱいだね。パブリンらしいよ。","ENG":"It's full of plants. Much like Pavlin's taste.","TWN":"到處都是植物啊，真是帕芙琳的風格。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이렇게 많은 식물들을 가꿨다는 건, 시간의 흐름에 대한 자각이 틀림없이 있었다는 거다.","JPN":"こんなにたくさん植物を育てたなら、時間の流れについても自覚があったはず。","ENG":"Seeing how so many plants have grown, she was also aware that time was flowing.","TWN":"能栽培這麼多植物，她一定對時間的流逝有很清晰的認知。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그럼 파블린은 역시 저 아이를 위해…","JPN":"じゃあパブリンは、やっぱりこの子のために……","ENG":"Then, for her child, Pavlin must–","TWN":"那麼帕芙琳果然是為了那個孩子……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"앗, 저 덤불…!","JPN":"あっ、あのいばらは……！","ENG":"Huh? That bush...!","TWN":"啊，那邊的樹叢……！"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니랑 함께 심은 라즈베리에요. 시기 좋게 열매도 맺었네요.","JPN":"お母さんと一緒に植えたラズベリーです。ちょうど実がなっていますね。","ENG":"These are raspberries that Mother and I planted. They also bore fruit.","TWN":"和媽媽一起種的覆盆子。正好結出了果實呢。"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"자요! 패리도 같이 먹죠!","JPN":"どうぞ！　パリーも召し上がれ！","ENG":"Here! Let's eat them together!","TWN":"悖悖！我們一起吃吧！"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GARDEN","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"침식지대에서 열매를 키우려 한다고?","JPN":"侵食地帯で果樹を育てる？","ENG":"You're going to try to grow fruit in a Corrupted Area?","TWN":"你想在侵蝕區域種植果實？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"어때요? 멋지지 않나요?","JPN":"どうです？　素敵でしょう？","ENG":"Doesn't it sound wonderful?","TWN":"怎麼樣？不覺得很神奇嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"빛바랬던 땅에 녹색 빛깔이 넘실대니 보기는 좋다만…","JPN":"色あせていた大地に緑が広がって、確かにいい景色だけど……","ENG":"It's nice to see lush greenery covering the tarnished lands, but...","TWN":"曾經褪色的土地如今變得綠意盎然，雖然看起來不錯……"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"침식파가 지금보다 강해지면 금방 시들어버릴 거다. 쓸데없는 짓일지도 몰라.","JPN":"侵食波が強くなったらすぐ枯れてしまうよ。努力が無駄になるかも。","ENG":"If the Corruption ray gets any stronger than now, they'll all wither away. It could be all for nothing.","TWN":"但如果侵蝕波突然變強，植物很快就會枯萎了。這也許是白費力氣呢。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"쓸데없어 보일 지도 모르지만, 숲도 풀 한 포기부터 시작하는 법이니까요.","JPN":"無駄に見えるかもしれませんけど、森も草から始まるものですから。","ENG":"That may be true, but all forests start out with a single blade of grass.","TWN":"或許看起來沒什麼用，但一片森林也是從一棵小草開始的。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"미래에 이곳에 푸른 초원이 있을 거라고 상상하면 조금도 아깝지 않은 걸요.","JPN":"未来のこの場所が、緑豊かな草原になっている光景を想像すると、この努力は少しも惜しくはありません。","ENG":"And when I imagine this place becoming a green pasture in the future, I don't think it'll be all for nothing.","TWN":"想像到未來這裡會有一片綠色的草原，就一點也不覺得可惜了。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"훌륭한 자세다! 파블린!","JPN":"素晴らしい姿勢だ、パブリン！","ENG":"Excellent attitude, Pavlin!","TWN":"很好的態度！帕芙琳！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};